using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

/// <summary>
/// Exposes application configuration as an MCP resource.
/// </summary>
public class ConfigResourceProvider
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["appName"] = "McpHttpServer",
        ["version"] = "1.0.0",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false,
        },
        ["maxRetries"] = 3,
    };

    [McpResource("config://app/settings", Name = "App Settings",
        Description = "Returns the current application configuration as JSON")]
    public static string GetAppSettings()
    {
        return JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes the provided message back to the caller.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(double a, double b) => a + b;
}

