    {
        Console.WriteLine("  Public Members:");
        foreach (var member in type.GetMembers(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static))
        {
            Console.WriteLine($"    {member.MemberType}: {member.Name}");
        }
    }
}

// Find attributes
Console.WriteLine("\n=== Resource Attributes ===\n");
var attrTypes = mcp.GetTypes()
    .Where(t => t.Name.Contains("Resource") && (t.IsClass && typeof(Attribute).IsAssignableFrom(t)))
    .OrderBy(t => t.Name)
    .ToList();

foreach (var type in attrTypes)
{
    Console.WriteLine($"{type.FullName}");
}

// Find extension methods
Console.WriteLine("\n=== WithResources Methods ===\n");
var extensionMethods = mcp.GetTypes()
    .Where(t => t.Name.Contains("Extensions"))
    .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
    .Where(m => m.Name == "WithResources" || m.Name == "WithResourcesFromAssembly")
    .ToList();

foreach (var method in extensionMethods)
{
    var ps = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"{method.DeclaringType?.Name}.{method.Name}({ps})");
}
